'use client';
import React from 'react';
import {
  Container,
  Box,
  Typography,
  Grid,
  Tabs,
  Tab,
  Chip,
} from '@mui/material';
import { motion } from 'framer-motion';
import CaseStudyCard from '@/components/CaseStudyCard/CaseStudyCard';

const Portfolio = () => {
  const [selectedCategory, setSelectedCategory] = React.useState('all');

  const caseStudies = [
    {
      id: 1,
      title: 'Residential Solar Installation',
      location: 'Pune, Maharashtra',
      capacity: '10 KW',
      savings: '₹45,000/year',
      description: 'Complete rooftop solar system installation for a 3BHK residential property in Pune.',
      category: 'Residential',
    },
    {
      id: 2,
      title: 'Commercial Rooftop System',
      location: 'Pune, Maharashtra',
      capacity: '50 KW',
      savings: '₹2,25,000/year',
      description: 'Large-scale commercial solar installation for a manufacturing unit in Pune.',
      category: 'Commercial',
    },
    {
      id: 3,
      title: 'Solar Water Heater Project',
      location: 'Pune, Maharashtra',
      capacity: '200L System',
      savings: '₹12,000/year',
      description: 'Solar water heating system for a residential complex with 20 units in Pune.',
      category: 'Residential',
    },
    {
      id: 4,
      title: 'Agricultural Solar Pump',
      location: 'Pune District, Maharashtra',
      capacity: '5 HP',
      savings: '₹60,000/year',
      description: 'Solar-powered irrigation pump for a 10-acre farm in Pune district.',
      category: 'Agricultural',
    },
    {
      id: 5,
      title: 'Industrial Solar Plant',
      location: 'Pune, Maharashtra',
      capacity: '100 KW',
      savings: '₹4,50,000/year',
      description: 'Industrial solar power plant with net metering in Pune industrial area.',
      category: 'Industrial',
    },
    {
      id: 6,
      title: 'Hybrid Solar System',
      location: 'Pune, Maharashtra',
      capacity: '25 KW',
      savings: '₹1,12,500/year',
      description: 'Hybrid solar system with battery backup for a commercial building in Pune.',
      category: 'Commercial',
    },
  ];

  const categories = ['all', 'Residential', 'Commercial', 'Industrial', 'Agricultural'];

  const filteredCaseStudies =
    selectedCategory === 'all'
      ? caseStudies
      : caseStudies.filter((study) => study.category === selectedCategory);

  return (
    <Box sx={{ pt: { xs: 8, md: 10 }, pb: 8 }}>
      {/* Hero Section */}
      <Box
        sx={{
          bgcolor: 'primary.main',
          color: 'white',
          py: 8,
          textAlign: 'center',
        }}
      >
        <Container maxWidth="md">
          <motion.div
            initial={{ opacity: 0, y: 30 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ duration: 0.6 }}
          >
            <Typography variant="h1" sx={{ fontWeight: 800, mb: 3 }}>
              Our Portfolio
            </Typography>
            <Typography variant="h5" sx={{ opacity: 0.9 }}>
              Explore our successful solar energy projects in Pune and surrounding areas
            </Typography>
          </motion.div>
        </Container>
      </Box>

      <Container maxWidth="xl" sx={{ mt: 8 }}>
        {/* Category Filter */}
        <Box sx={{ mb: 6, display: 'flex', justifyContent: 'center', flexWrap: 'wrap', gap: 2 }}>
          {categories.map((category) => (
            <Chip
              key={category}
              label={category.charAt(0).toUpperCase() + category.slice(1)}
              onClick={() => setSelectedCategory(category)}
              color={selectedCategory === category ? 'primary' : 'default'}
              sx={{
                px: 2,
                py: 3,
                fontSize: '1rem',
                fontWeight: selectedCategory === category ? 700 : 500,
                cursor: 'pointer',
              }}
            />
          ))}
        </Box>

        {/* Case Studies Grid */}
        <Grid container spacing={4}>
          {filteredCaseStudies.map((caseStudy, index) => (
            <Grid item xs={12} sm={6} md={4} key={caseStudy.id}>
              <CaseStudyCard caseStudy={caseStudy} index={index} />
            </Grid>
          ))}
        </Grid>

        {filteredCaseStudies.length === 0 && (
          <Box sx={{ textAlign: 'center', py: 8 }}>
            <Typography variant="h5" color="text.secondary">
              No projects found in this category
            </Typography>
          </Box>
        )}

        {/* Stats Section */}
        <Box
          sx={{
            mt: 8,
            bgcolor: 'background.default',
            borderRadius: 4,
            p: 6,
            textAlign: 'center',
          }}
        >
          <Typography variant="h3" sx={{ fontWeight: 800, mb: 4 }}>
            Portfolio Highlights
          </Typography>
          <Grid container spacing={4}>
            {[
              { label: 'Total Projects', value: '25+' },
              { label: 'Total Capacity', value: '500KW+' },
              { label: 'Service Area', value: 'Pune & Nearby' },
              { label: 'Customer Satisfaction', value: '100%' },
            ].map((stat, index) => (
              <Grid item xs={6} md={3} key={index}>
                <motion.div
                  initial={{ opacity: 0, scale: 0.8 }}
                  whileInView={{ opacity: 1, scale: 1 }}
                  viewport={{ once: true }}
                  transition={{ duration: 0.5, delay: index * 0.1 }}
                >
                  <Typography variant="h3" sx={{ fontWeight: 800, color: 'primary.main', mb: 1 }}>
                    {stat.value}
                  </Typography>
                  <Typography variant="body1" color="text.secondary">
                    {stat.label}
                  </Typography>
                </motion.div>
              </Grid>
            ))}
          </Grid>
        </Box>
      </Container>
    </Box>
  );
};

export default Portfolio;

