'use client';
import React from 'react';
import { Card, CardContent, CardMedia, Typography, Box, Chip } from '@mui/material';
import { LocationOn, TrendingUp } from '@mui/icons-material';
import { motion } from 'framer-motion';

interface CaseStudyCardProps {
  caseStudy?: any;
  index?: number;
}

const CaseStudyCard = ({ caseStudy, index = 0 }: CaseStudyCardProps) => {
  const defaultCaseStudy = {
    id: 1,
    title: 'Residential Solar Installation',
    location: 'Mumbai, Maharashtra',
    capacity: '10 KW',
    savings: '₹45,000/year',
    image: 'https://images.unsplash.com/photo-1464226184884-fa280b87c399?w=600',
    description: 'Complete rooftop solar system installation for a 3BHK residential property.',
    category: 'Residential',
  };

  const data = caseStudy || defaultCaseStudy;

  return (
    <motion.div
      initial={{ opacity: 0, y: 30 }}
      whileInView={{ opacity: 1, y: 0 }}
      viewport={{ once: true }}
      transition={{ duration: 0.5, delay: index * 0.1 }}
    >
      <Card
        sx={{
          height: '100%',
          display: 'flex',
          flexDirection: 'column',
          overflow: 'hidden',
        }}
      >
        <CardMedia
          component="div"
          sx={{
            height: 250,
            background: `linear-gradient(135deg, #FFA50020, #2B7A0B20)`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            fontSize: '5rem',
            position: 'relative',
          }}
        >
          ☀️
        </CardMedia>
        <CardContent sx={{ flexGrow: 1 }}>
          <Box sx={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', mb: 2 }}>
            <Typography variant="h5" sx={{ fontWeight: 700, flex: 1 }}>
              {data.title}
            </Typography>
            <Chip
              label={data.category}
              size="small"
              sx={{
                bgcolor: 'primary.main',
                color: 'white',
                fontWeight: 600,
              }}
            />
          </Box>
          <Box sx={{ display: 'flex', alignItems: 'center', gap: 1, mb: 2 }}>
            <LocationOn sx={{ color: 'text.secondary', fontSize: 18 }} />
            <Typography variant="body2" color="text.secondary">
              {data.location}
            </Typography>
          </Box>
          <Typography variant="body2" color="text.secondary" sx={{ mb: 3 }}>
            {data.description}
          </Typography>
          <Box
            sx={{
              display: 'flex',
              gap: 3,
              pt: 2,
              borderTop: '1px solid',
              borderColor: 'divider',
            }}
          >
            <Box>
              <Typography variant="body2" color="text.secondary">
                Capacity
              </Typography>
              <Typography variant="h6" sx={{ fontWeight: 700, color: 'primary.main' }}>
                {data.capacity}
              </Typography>
            </Box>
            <Box>
              <Typography variant="body2" color="text.secondary">
                Annual Savings
              </Typography>
              <Box sx={{ display: 'flex', alignItems: 'center', gap: 0.5 }}>
                <TrendingUp sx={{ color: 'secondary.main', fontSize: 18 }} />
                <Typography variant="h6" sx={{ fontWeight: 700, color: 'secondary.main' }}>
                  {data.savings}
                </Typography>
              </Box>
            </Box>
          </Box>
        </CardContent>
      </Card>
    </motion.div>
  );
};

export default CaseStudyCard;

